// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;
interface IUserregistry{
    function isvarifieduser(address _user)external view returns(bool);
}
contract charging_request
{
 IUserregistry public registry;
 address public validator;
 constructor(address _registry){
    registry=IUserregistry(_registry);
    validator = msg.sender;
 }
 enum Status{
    OPEN,
    ACCEPTED,
    COMPLETED,
    CANCELED
 }
 struct Request{
    uint256 id;
    address reciever;
    uint256 energyrequired;
    uint256 priceperkilo;
    string location;
    Status status;
 }
 mapping(uint256=>Request)public request;
 uint256 public requestCount;

event RequestCreated(uint256 indexed requestId, address indexed receiver); 
event requestcancelled(uint256 indexed request_id);
modifier onlyValidatorOrUser() {
    require(
        registry.isvarifieduser(msg.sender) || msg.sender == validator,
        "not allowed"
    );
    _;
}
 modifier onlyvariefieduser(){
    require(registry.isvarifieduser(msg.sender),"only variefied user allowe");
    _;
 }

function createrequest(uint256 energy_required,uint256 priceofenergyperkph,string memory _location)external onlyvariefieduser
{
require(energy_required>0,"please insert valid energy_require");
require(priceofenergyperkph>0,"please enter the valid energy");

requestCount++;
request[requestCount]=Request({
    id:requestCount,
    reciever:msg.sender,
    energyrequired:energy_required,
    priceperkilo:priceofenergyperkph,
    location:_location,
    status:Status.OPEN
  
});
emit RequestCreated(requestCount,msg.sender);
}

function canceled_request(uint256 _requisted_id) external{
    Request storage req=request[_requisted_id];
    require(req.reciever==msg.sender,"not request owner");
    require(req.status==Status.OPEN,"not possible to cancelled");
    req.status=Status.CANCELED;
    emit requestcancelled(_requisted_id);
}
function getRequest(uint256 _id)external view returns(Request memory)
{
 return request[_id];
}
function updatestatus(uint256 _id, Status _status) external onlyValidatorOrUser {
    require(_id > 0 && _id <= requestCount, "Invalid request id");

    Request storage req = request[_id];
    require(req.status != Status.CANCELED, "Request already canceled");

    req.status = _status;
}
}

contracts/EnergyValidation.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IChargingRequest{

    enum Status{
        OPEN,
        ACCEPTED,
        COMPLETED,
        CANCELED
    }

    struct Request{
        uint256 id;
        address reciever;
        uint256 energyrequired;
        uint256 priceperkilo;
        string location;
        Status status;
    }

    function getRequest(uint256 _id) external view returns(Request memory);

    function updatestatus(uint256 _id, Status _status) external;
}

contract EnergyValidation
{
    address public validator;
    IChargingRequest public charging;

    constructor(address _chargingrequest){
        validator = msg.sender;
        charging = IChargingRequest(_chargingrequest);
    }

    modifier onlyvalidator(){
        require(msg.sender == validator,"only validator is allowed");
        _;
    }

    struct Session
    {
        bool start;
        bool completed;
        uint256 energydelivered;
    }

    mapping(uint256 => Session) public _Session;

    event chargingstarted(uint256 _requestid);
    event chargingcompleted(uint256 _requestid,uint256 energydelivered);

    function started(uint256 _requestid) external onlyvalidator{
       IChargingRequest.Request memory req = charging.getRequest(_requestid);

    require(
        req.status == IChargingRequest.Status.ACCEPTED,
        "only accepted request are allowed"
    );

        _Session[_requestid].start = true;

        emit chargingstarted(_requestid); 
    }

    function completed(uint256 _requestedid,uint256 _energydelivered) external onlyvalidator
    {
        require(_Session[_requestedid].start,"first start the energy");
        require(!_Session[_requestedid].completed,"charging already completed");

        _Session[_requestedid].completed = true;
        _Session[_requestedid].energydelivered = _energydelivered;

        charging.updatestatus(
            _requestedid,
            IChargingRequest.Status.COMPLETED
        );

        emit chargingcompleted(_requestedid,_energydelivered);
    }

    function iscompleted(uint256 _requestedid) external view returns(bool){
        return _Session[_requestedid].completed;
    }

    function getdeliveredenergy(uint256 _requestedid) external view returns(uint256){
        return _Session[_requestedid].energydelivered;
    }
}

contracts/EscrowPayment.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IChargingRequest{
    enum Status{
        OPEN,
        ACCEPTED,
        COMPLETED,
        CANCELED
    }

    function getRequest(uint256) external view returns( 
        uint256 id,
        address reciever,
        uint256 energyrequired,
        uint256 priceperkilo,
        string memory location,
        Status status
    );
}

interface IMatchingContract{
    function getMatch(uint256 _requestid) external view returns(
        uint256 requestid,
        address reciever,
        address donor,
        bool active
    );
}

contract EscrowPayment{

    address public admin;
    IChargingRequest public charging;
    IMatchingContract public matching;

    mapping(uint256 => uint256) public Escrowbalance;

    modifier onlyadmin(){
        require(msg.sender == admin,"only admin allowed");
        _;
    }

    event Paymentdeposited(uint256 indexed _requestid,address reciever,uint256 amount);
    event Paymentrelease(uint256 indexed requestid,address donor,uint256 amount);
    event refundpayment(uint256 indexed _requestid,address reciever,uint256 amount);

    constructor(address _charging,address _matching){
        admin = msg.sender;
        charging = IChargingRequest(_charging);
        matching = IMatchingContract(_matching);
    }

    function deposite(uint256 _requestedid) external payable{

        (
            ,
            address reciever,
            uint256 energyrequired,
            uint256 priceperkilo,
            ,
            IChargingRequest.Status status
        ) = charging.getRequest(_requestedid);

        require(msg.sender == reciever,"only reciever can deposite");
        require(status == IChargingRequest.Status.ACCEPTED,"only accepted request allowed");
        require(Escrowbalance[_requestedid] == 0,"already deposited");

        uint256 totalcost = energyrequired * priceperkilo;

        require(msg.value == totalcost,"incorrect payment amount");

        Escrowbalance[_requestedid] = msg.value;

        emit Paymentdeposited(_requestedid,msg.sender,msg.value);
    }

    function paymentrelease(uint256 _requestedid) external onlyadmin{

        (
            ,
            ,
            address donor,
            bool active
        ) = matching.getMatch(_requestedid);

        require(active,"matching not found");

        uint256 amount = Escrowbalance[_requestedid];

        require(amount > 0,"no funds");

        Escrowbalance[_requestedid] = 0;

        payable(donor).transfer(amount);

        emit Paymentrelease(_requestedid,donor,amount);
    }

    function refund(uint256 _requestedid) external onlyadmin{

        (
            ,
            address reciever,
            ,
            ,
            ,
            IChargingRequest.Status status
        ) = charging.getRequest(_requestedid);

        uint256 amount = Escrowbalance[_requestedid];

        require(amount > 0,"no fund");

        Escrowbalance[_requestedid] = 0;

        payable(reciever).transfer(amount);

        emit refundpayment(_requestedid,reciever,amount);
    }
}

contracts/GovernanceAdmin.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/* ========= INTERFACES ========= */

interface IPlatformFee {
    function updateFeePercent(uint256 newFee) external;
}

interface IEnergyValidation {
    function changeValidator(address newValidator) external;
}

interface IEscrowPayment {
    function pauseEscrow(bool status) external;
}

/* ========= GOVERNANCE ADMIN ========= */

contract GovernanceAdmin {

    address public owner;

    address public platformFee;
    address public energyValidation;
    address public escrow;

    bool public systemPaused;

    /* ========= EVENTS ========= */

    event OwnershipTransferred(address indexed oldOwner, address indexed newOwner);
    event SystemPauseChanged(bool status);
    event PlatformFeeUpdated(uint256 newFee);
    event ValidatorUpdated(address newValidator);

    /* ========= CONSTRUCTOR ========= */

    constructor(
        address _platformFee,
        address _energyValidation,
        address _escrow
    ) {
        owner = msg.sender;

        platformFee = _platformFee;
        energyValidation = _energyValidation;
        escrow = _escrow;
    }

    /* ========= MODIFIER ========= */

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner allowed");
        _;
    }

    /* ========= TRANSFER OWNERSHIP ========= */

    function transferOwnership(address newOwner)
        external
        onlyOwner
    {
        require(newOwner != address(0), "Invalid address");

        address oldOwner = owner;
        owner = newOwner;

        emit OwnershipTransferred(oldOwner, newOwner);
    }

    /* ========= PAUSE SYSTEM ========= */

    function setSystemPause(bool status)
        external
        onlyOwner
    {
        systemPaused = status;

        IEscrowPayment(escrow).pauseEscrow(status);

        emit SystemPauseChanged(status);
    }

    /* ========= UPDATE PLATFORM FEE ========= */

    function updatePlatformFee(uint256 newFee)
        external
        onlyOwner
    {
        IPlatformFee(platformFee).updateFeePercent(newFee);

        emit PlatformFeeUpdated(newFee);
    }

    /* ========= CHANGE ENERGY VALIDATOR ========= */

    function changeValidator(address newValidator)
        external
        onlyOwner
    {
        IEnergyValidation(energyValidation).changeValidator(newValidator);

        emit ValidatorUpdated(newValidator);
    }

}

