// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

interface IuserRegistry{
    function isvarifieduser(address _user) external view returns(bool);
}

interface Ichargingrequest{

    enum Status{
        OPEN,
        ACCEPTED,
        COMPLETED,
        CANCELED
    }

    struct Request{
        uint256 id;
        address reciever;
        uint256 energyrequired;
        uint256 priceperkilo;
        string location;
        Status status;
    }

    function getRequest(uint256 _id) external view returns(Request memory);
}

contract MatchingContract{

    IuserRegistry public registry;
    Ichargingrequest public chargingcontract;

    constructor(address _registry,address _chargingcontract)
    {
       registry = IuserRegistry(_registry);
       chargingcontract = Ichargingrequest(_chargingcontract);
    }

    struct Match{
        uint256 requestid;
        address reciever;
        address donor;
        bool active;
    }

   // mapping(uint256=>address)public doneraddress;

    mapping(uint256=>Match) public matching;

    mapping(uint256=>address) public requestDonor;

    event acceptedrequest(uint256 indexed request_id,address indexed receiver);

    modifier onlyverifieddonoe(){
        require(registry.isvarifieduser(msg.sender),"only varified donor allowed");
        _;
    }

    function acceptrequest(uint256 _requestedid) external onlyverifieddonoe{

        Ichargingrequest.Request memory req = chargingcontract.getRequest(_requestedid);

        uint256 id = req.id;
        address reciever = req.reciever;
        Ichargingrequest.Status status = req.status;

        require(id != 0,"request is not found");
        require(status == Ichargingrequest.Status.OPEN,"request is not open");

        //  require(doneraddress[ _requestedid] == address(0),
        // "Already accepted");

        requestDonor[_requestedid] = msg.sender;

        matching[_requestedid] = Match({
            requestid:_requestedid,
            reciever:reciever,
            donor:msg.sender,
            active:true
        });

        emit acceptedrequest(_requestedid,msg.sender);
    }

    function getMatch(uint256 _requestId)
        external
        view
        returns (Match memory)
    {
        return matching[_requestId];
    }

//    function getDonor(uint256 requestId)
//     external
//     view
//     returns(address)
// {
//     return matches[requestId].donor;
// }

}

contracts/PlatformFee.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

contract PlatformFee {

    address public owner;
    address public escrowContract;

    uint256 public feePercent;   // Example: 2 = 2%

    /* ========= EVENTS ========= */

    event EscrowUpdated(address indexed newEscrow);
    event FeePercentUpdated(uint256 newPercent);
    event FeeCollected(uint256 amount);
    event Withdraw(address indexed owner, uint256 amount);

    /* ========= CONSTRUCTOR ========= */

    constructor(uint256 _feePercent) {
        owner = msg.sender;
        feePercent = _feePercent;
    }

    /* ========= MODIFIERS ========= */

    modifier onlyOwner() {
        require(msg.sender == owner, "Only owner allowed");
        _;
    }

    modifier onlyEscrow() {
        require(msg.sender == escrowContract, "Only escrow allowed");
        _;
    }

    /* ========= SET ESCROW CONTRACT ========= */

    function setEscrowContract(address _escrow)
        external
        onlyOwner
    {
        require(_escrow != address(0), "Invalid address");

        escrowContract = _escrow;

        emit EscrowUpdated(_escrow);
    }

    /* ========= UPDATE FEE PERCENT ========= */

    function updateFeePercent(uint256 _newPercent)
        external
        onlyOwner
    {
        require(_newPercent <= 10, "Fee too high"); 
        feePercent = _newPercent;

        emit FeePercentUpdated(_newPercent);
    }

    /* ========= CALCULATE PLATFORM FEE ========= */

    function calculateFee(uint256 amount)
        external
        view
        returns(uint256)
    {
        return (amount * feePercent) / 100;
    }

    /* ========= RECEIVE PLATFORM FEE ========= */

    function collectFee()
        external
        payable
        onlyEscrow
    {
        require(msg.value > 0, "No fee sent");

        emit FeeCollected(msg.value);
    }

    /* ========= WITHDRAW FEES ========= */

    function withdrawFees()
        external
        onlyOwner
    {
        uint256 balance = address(this).balance;

        require(balance > 0, "No balance");

        payable(owner).transfer(balance);

        emit Withdraw(owner, balance);
    }
}

contracts/ReputationSystem.sol.content:
// SPDX-License-Identifier: MIT
pragma solidity ^0.8.20;

/* ========= INTERFACE ========= */

interface IEscrowPayment {

    function paymentReleased(uint256 requestId)
        external
        view
        returns(bool);
}

/* ========= REPUTATION SYSTEM ========= */

contract ReputationSystem {

    IEscrowPayment public escrow;

    constructor(address _escrow) {
        escrow = IEscrowPayment(_escrow);
    }

    /* ========= STRUCT ========= */

    struct Reputation {
        uint256 totalRating;
        uint256 ratingCount;
    }

    mapping(address => Reputation) public reputations;

    // prevent double rating
    mapping(uint256 => mapping(address => bool)) public rated;

    /* ========= EVENTS ========= */

    event UserRated(
        uint256 indexed requestId,
        address indexed rater,
        address indexed user,
        uint256 rating
    );

    /* ========= RATE USER ========= */

    function rateUser(
        uint256 requestId,
        address user,
        uint256 rating
    )
        external
    {
        require(
            escrow.paymentReleased(requestId),
            "Payment not released"
        );

        require(
            rating >= 1 && rating <= 5,
            "Rating must be 1-5"
        );

        require(
            !rated[requestId][msg.sender],
            "Already rated"
        );

        reputations[user].totalRating += rating;
        reputations[user].ratingCount += 1;

        rated[requestId][msg.sender] = true;

        emit UserRated(
            requestId,
            msg.sender,
            user,
            rating
        );
    }

    /* ========= GET AVERAGE RATING ========= */

    function getAverageRating(address user)
        external
        view
        returns(uint256)
    {
        Reputation memory rep = reputations[user];

        if(rep.ratingCount == 0){
            return 0;
        }

        return rep.totalRating / rep.ratingCount;
    }
}

